sql:
SELECT COUNT(*) 
FROM blockchain_updates 
WHERE status = 'completed';

SELECT timestamp, price, amount
FROM exchange_trades
ORDER BY timestamp DESC;

SELECT SUM(amount) AS total_amount_traded, MAX(price) AS max_price
FROM exchange_trades
WHERE exchange_id = 0;

SELECT block_height, error_message
FROM blockchain_updates
WHERE status = 'failed';

SELECT MIN(min_order_size) AS min_order_size, MAX(max_order_size) AS max_order_size
FROM exchange_pairs
WHERE exchange_id = 1;

SELECT address, balance
FROM addresses
ORDER BY balance DESC;

SELECT timestamp, balance_normalized
FROM balances
WHERE balance_id = 1;
